// src/components/PropertyDetail.js
import React from 'react';

const PropertyDetail = ({ property, onBack }) => {
  // ✅ Render nothing if property is null or undefined
  if (!property) return null;

  return (
    <div className="property-detail" data-testid="property-detail">
      <button onClick={onBack} data-testid="back-button">← Back to List</button>
      <h2>{property.title}</h2>
      <p><strong>Description:</strong> {property.description}</p>
      <p><strong>Price:</strong> ${property.price.toLocaleString()}</p>
      <p><strong>Bedrooms:</strong> {property.bedrooms}</p>
      <p><strong>Bathrooms:</strong> {property.bathrooms}</p>
      <p><strong>Area:</strong> {property.area} sq ft</p>
      <p><strong>Address:</strong> {property.address}, {property.city}, {property.state}</p>
      <p><strong>Zip Code:</strong> {property.zipCode}</p>
      <p><strong>Property Type:</strong> {property.propertyType}</p>
      <p><strong>Listing Date:</strong> {property.listingDate}</p>
      <p><strong>Available:</strong> <span aria-label="Available:">{property.isAvailable ? 'Yes' : 'No'}</span></p>
    </div>
  );
};

export default PropertyDetail;
